@Component({ changeDetection: ChangeDetectionStrategy.OnPush })
export class UserCard {
  user = input.required<User>();  // Signal input (Angular 17+)
  delete = output<string>();      // Typed output
  edit = output<User>();
}

type LoadingState<T> =
  | { status: 'idle' }
  | { status: 'loading' }
  | { status: 'success'; data: T }
  | { status: 'error'; error: string };
// Template: @switch (state().status) { @case ('loading') { <spinner/> } ... }

// Actions
export const increment = createAction('[Counter] Increment');
export const decrement = createAction('[Counter] Decrement');
// Feature
export const counterFeature = createFeature({
  name: 'counter',
  reducer: createReducer(0,
    on(increment, state => state + 1),
    on(decrement, state => state - 1)
  )
});
// Auto-generated: counterFeature.selectCounterState

@Component({
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<p>Count: {{ count() }}</p><button (click)="increment()">+1</button>`
})
export class Counter {
  count = signal(0);
  increment() { this.count.update(n => n + 1); }
  // Signal update triggers OnPush re-render automatically!
}

export const API_CONFIG = new InjectionToken<ApiConfig>('API_CONFIG', {
  providedIn: 'root',
  factory: () => ({
    baseUrl: inject(IS_PRODUCTION) ? 'https://api.prod.com' : 'http://localhost:3000',
    timeout: 5000
  })
});

